/**
 * Returns the captured price-history points for the last `hours` hours
(default 48, max 168), plus a 24-hour forecast computed from the
deterministic surge model. History points themselves may have been
captured live from Yandex Go or computed by the same fallback model;
each point carries its own `source` flag.

 * @summary Historical & forecasted tariffs for a single route
 */
export const getGetTariffRouteHistoryUrl = (
  id: string,
  params?: GetTariffRouteHistoryParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/tariff-grid/route/${id}/history?${stringifiedParams}`
    : `/api/tariff-grid/route/${id}/history`;
};

